form:Form.form:Scripts:
		function LoadForm()
{
	if (Ctrl('oi_empresa').GetCValue() != "")
	{
		Ctrl('oi_personal_emp').SetCValue("");
		CtrlEnabled('oi_personal_emp', true);		
	}
	else
	{
		Ctrl('oi_personal_emp').SetCValue("");
		CtrlEnabled('oi_personal_emp', false);		
	}
	if (Ctrl('l_activa_reloj').GetCValue() == "1")
	{		
		AutoClock();	
		CtrlEnabled('f_fechahora', false);	
	}
}

function EnableControls(me)
{
	if (me.GetCValue() != "")
	{
		CtrlEnabled('oi_personal_emp', true);		
	}
	else
	{		
		Ctrl('oi_personal_emp').SetCValue("");
		CtrlEnabled('oi_personal_emp', false);		
	}
}

function EnableClock()
{	
	if (Ctrl('l_activa_reloj').GetXValue() == '0')
	{
		Ctrl('f_fechahora').SetXValue('');
		CtrlEnabled('f_fechahora', true);
	}
	else
	{
		AutoClock();
		CtrlEnabled('f_fechahora', false);
	}
}

function AutoClock()
{
	try
	{		
		if (Ctrl('l_activa_reloj').GetXValue() == '1')
		{
		  momentoActual = new Date();  
		  horaImprimible = datetime2str(momentoActual).substr(0,12)+"00";    		  
		  Ctrl('f_fechahora').SetXValue(horaImprimible);	
		  setTimeout("AutoClock()",(60-momentoActual.getSeconds())*1000); 
		}
	}
	catch(e)
	{
	}	
}

function GetLegajo()
{	
	if (Ctrl('oi_personal_emp').GetCValue() != '')
	{		
		var legajo;				
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();

		legajo = nSQL.GetOBJ(Ctrl("main").getResource("QRY_LEGAJO_RELOJ"), "<PARAM oi_personal_emp=\""+Ctrl("oi_personal_emp").GetXValue()+"\" />"); 		
		Ctrl("e_numero_legajo").SetXValue(legajo.e_nro_legajo_reloj);				
	}
}

function Ingreso()
{	
	if(!ValParam())
		return false;
	if(!ValUser())
		return false;	
	momentoActual = new Date();  
	horaImprimible = datetime2str(momentoActual).substr(0,12)+"00";    		  		  
	Ctrl('now').SetXValue(horaImprimible);
	Ctrl('c_fichadasing').SetCValue(Ctrl('f_fechahora').GetXValue() + Ctrl('e_numero_legajo').GetXValue() + "M" + "E");	
	Ctrl('c_tipo').SetCValue('E');
	return true;
}

function Egreso()
{
	if(!ValParam())
		return false;
	if(!ValUser())
		return false;
	momentoActual = new Date();  
	horaImprimible = datetime2str(momentoActual).substr(0,12)+"00";    		  		  
	Ctrl('now').SetXValue(horaImprimible);
	Ctrl('c_fichadasing').SetCValue(Ctrl('f_fechahora').GetXValue() + Ctrl('e_numero_legajo').GetXValue() + "M" + "S");
	Ctrl('c_tipo').SetCValue('S');
	return true;	
}

function onvalidate() {
	if (Ctrl('f_fechahora').TypedValue() < str2date(Ctrl('f_ingreso').GetXValue())) {
		Ctrl('f_fechahora').SetError('La fecha de la fichada es anterior a la fecha de ingreso del Legajo.');
		return false;
	}
	return true;
}

function ValParam()
{		
	if(Ctrl('PosEditFic').GetXValue() == "" && Ctrl('PreEditFic').GetXValue())
		return true

	momentoActual = new Date();

	if(Ctrl('PosEditFic').GetXValue() != "")
	{
		fechaComparePos = new Date(momentoActual.getFullYear(), momentoActual.getMonth(), momentoActual.getDate() + 1 +  parseInt(Ctrl('PosEditFic').GetXValue()));

		if (Ctrl('f_fechahora').TypedValue() > fechaComparePos) 
		{
			alert('La fecha de la fichada supera la cantidad de días posteriores a la fecha actual permitidos ('+Ctrl('PosEditFic').GetXValue()+').');
			return false;
		}
	}

	if(Ctrl('PreEditFic').GetXValue() != "")
	{
		fechaComparePre = new Date(momentoActual.getFullYear(), momentoActual.getMonth(), momentoActual.getDate() - 1 - parseInt(Ctrl('PreEditFic').GetXValue()));

		if (Ctrl('f_fechahora').TypedValue() < fechaComparePre) 
		{
			alert('La fecha de la fichada supera la cantidad de días previos a la fecha actual permitidos ('+Ctrl('PreEditFic').GetXValue()+').');
			return false;
		}
	}


	return true;	
}

function ValUser()
{			
	if(Ctrl('EditMyFic').GetXValue() != "1")
		return true

	if (Ctrl('oi_personal_emp').GetCValue() != '')
	{		
		var user;				
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();

		user = nSQL.GetOBJ(Ctrl("main").getResource("QRY_USER"), "<PARAM oi_personal_emp=\""+Ctrl("oi_personal_emp").GetXValue()+"\" />"); 				
		if(Ctrl("etty").GetXValue() == user.oi_usuario_sistema)
		{		
			alert('No se permite agregar fichadas para el propio usuario.');
			return false;
		}
	}
	return true;	
}
